window.renderChecklistItemRow=function(e,t,n,i,a,o){const d=i?`custom-${n}`:`${t}-${n}`,l=a[d]||{},r=l.status||"";return`\n        <div class="card checklist-item" id="row-${d}" style="margin-bottom: 0.5rem; padding: 1rem; border-left: 4px solid #e2e8f0;">\n             <div style="display: grid; grid-template-columns: 30px 80px 1fr 180px; gap: 1rem; align-items: start;">\n                <div style="display: flex; align-items: center;">\n                    <input type="checkbox" class="item-checkbox" data-unique-id="${d}" style="width: 18px; height: 18px; cursor: pointer;" title="Select this item for bulk action">\n                </div>\n                <div style="font-weight: bold; color: var(--primary-color);">${e.clause||"N/A"}</div>\n                <div>\n                    <div style="font-weight: 500; margin-bottom: 0.25rem;">${window.UTILS.escapeHtml(e.requirement)}</div>\n                    <div style="position: relative;">\n                        <input type="text" id="comment-${d}" placeholder="Auditor remarks..." class="form-control form-control-sm" value="${window.UTILS.escapeHtml(l.comment||"")}" style="margin-bottom: 0; padding-right: 35px;">\n                        <button type="button" id="mic-btn-${d}" data-action="startDictation" data-id="${d}" style="position: absolute; right: 0; top: 0; height: 100%; width: 35px; background: none; border: none; cursor: pointer; color: var(--text-secondary); display: flex; align-items: center; justify-content: center;" title="Dictate to Remarks">\n                            <i class="fa-solid fa-microphone"></i>\n                        </button>\n                    </div>\n                </div>\n                <div style="display: flex; gap: 0.5rem; justify-content: flex-end;">\n                    <button type="button" class="btn-icon btn-na status-btn" data-unique-id="${d}" data-status="${window.CONSTANTS.STATUS.NA}" title="Not Applicable">N/A</button>\n                    <button type="button" class="btn-icon btn-ok status-btn" data-unique-id="${d}" data-status="${window.CONSTANTS.STATUS.CONFORM}" title="Conformity" aria-label="Confirm"><i class="fa fa-check"></i></button>\n                    <button type="button" class="btn-icon btn-nc status-btn" data-unique-id="${d}" data-status="${window.CONSTANTS.STATUS.NC}" title="Non-Conformity" aria-label="Close"><i class="fa fa-times"></i></button>\n                </div>\n             </div>\n             \n             \x3c!-- Hidden status input --\x3e\n             <input type="hidden" class="status-input" data-checklist="${t}" data-item="${n}" data-custom="${i}" data-clause="${window.UTILS.escapeHtml(e.clause||"")}" data-requirement="${window.UTILS.escapeHtml(e.requirement||"")}" id="status-${d}" value="${r}">\n             \n             \x3c!-- NCR Panel (Conditional) --\x3e\n             <div id="ncr-panel-${d}" class="ncr-panel" style="display: ${"nc"===r?"block":"none"}; background: #fff1f2; border: 1px solid #fecaca; padding: 1rem; margin-top: 1rem; border-radius: 6px;">\n                 <h5 style="color: var(--danger-color); margin-bottom: 0.5rem; display: flex; align-items: center;"><i class="fa-solid fa-triangle-exclamation" style="margin-right: 0.5rem;"></i> Non-Conformity Details</h5>\n                 <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 1rem; margin-bottom: 0.5rem;">\n                     <div>\n                         <label style="font-size: 0.8rem;">Severity</label>\n                         <div style="display: flex; gap: 5px;">\n                             <select id="ncr-type-${d}" class="form-control form-control-sm">\n                                 <option value="${window.CONSTANTS.NCR_TYPES.OBSERVATION}" ${l.ncrType&&l.ncrType!==window.CONSTANTS.NCR_TYPES.OBSERVATION?"":"selected"}>Observation (OBS)</option>\n                                 <option value="${window.CONSTANTS.NCR_TYPES.OFI}" ${l.ncrType===window.CONSTANTS.NCR_TYPES.OFI?"selected":""}>Opportunity for Improvement (OFI)</option>\n                                 <option value="${window.CONSTANTS.NCR_TYPES.MINOR}" ${l.ncrType===window.CONSTANTS.NCR_TYPES.MINOR?"selected":""}>Minor NC</option>\n                                 <option value="${window.CONSTANTS.NCR_TYPES.MAJOR}" ${l.ncrType===window.CONSTANTS.NCR_TYPES.MAJOR?"selected":""}>Major NC</option>\n                             </select>\n                             <button type="button" class="btn btn-sm btn-info" data-action="toggleDisplay" data-id="criteria-${d}" title="View Classification Matrix (ISO 17021-1)">\n                                <i class="fa-solid fa-scale-balanced"></i>\n                             </button>\n                         </div>\n                         <div id="criteria-${d}" style="display: none; position: absolute; background: white; border: 1px solid #ccc; padding: 10px; z-index: 100; width: 300px; box-shadow: 0 4px 6px rgba(0,0,0,0.1); border-radius: 4px; font-size: 0.8rem; margin-top: 5px;">\n                            <strong>ISO 17021-1 Criteria</strong>\n                            <div style="margin-top:5px; border-left: 3px solid var(--danger-color); padding-left: 5px; background: #fff5f5;">\n                                <strong>Major:</strong> ${window.CONSTANTS.NCR_CRITERIA.MAJOR.description}\n                            </div>\n                            <div style="margin-top:5px; border-left: 3px solid var(--warning-color); padding-left: 5px; background: #fffaf0;">\n                                <strong>Minor:</strong> ${window.CONSTANTS.NCR_CRITERIA.MINOR.description}\n                            </div>\n                            <div style="text-align: right; margin-top: 5px;"><small style="color: blue; cursor: pointer;" data-action="hideGrandparent">Close</small></div>\n                         </div>\n                     </div>\n                     <div style="display: flex; flex-direction: column;">\n                         <label style="font-size: 0.8rem;">Evidence Image <span style="font-weight: normal; color: var(--text-secondary);">(max 5MB)</span></label>\n                        <div style="display: flex; gap: 5px;">\n                             <button type="button" class="btn btn-sm btn-outline-secondary" style="border-style: dashed; flex: 1;" data-action="clickElement" data-id="img-${d}">\n                                 <i class="fa-solid fa-file-image"></i> Upload\n                             </button>\n                             <button type="button" class="btn btn-sm btn-outline-secondary" style="flex: 1;" data-action="handleCameraButton" data-id="${d}" title="Capture photo from mobile camera or webcam">\n                                 <i class="fa-solid fa-camera"></i> Camera\n                             </button>\n                             <button type="button" class="btn btn-sm btn-outline-primary" style="flex: 1;" data-action="captureScreenEvidence" data-id="${d}" title="Capture from Zoom/Teams Screen Share">\n                                 <i class="fa-solid fa-desktop"></i> Screen\n                             </button>\n                         </div>\n                         <input type="file" id="img-${d}" accept="image/*" style="display: none;" data-action-change="handleEvidenceUpload" data-arg1="${d}" data-arg2="this">\n                         <input type="file" id="cam-${d}" accept="image/*" capture="environment" style="display: none;" data-action-change="handleEvidenceUpload" data-arg1="${d}" data-arg2="this">\n                     </div>\n                 </div>\n                 \n                 \x3c!-- Cross-Reference: Designation & Department --\x3e\n                 <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 1rem; margin-bottom: 0.5rem;">\n                     <div>\n                         <label style="font-size: 0.8rem;">Interviewee Designation</label>\n                         <input type="text" id="ncr-designation-${d}" class="form-control form-control-sm" placeholder="e.g., Quality Manager" value="${l.designation||""}">\n                     </div>\n                     <div>\n                         <label style="font-size: 0.8rem;">Department</label>\n                         <select id="ncr-department-${d}" class="form-control form-control-sm">\n                            <option value="">-- Select --</option>\n                            ${o.map(e=>`<option value="${e}" ${l.department===e?"selected":""}>${e}</option>`).join("")}\n                            ${l.department&&!o.includes(l.department)?`<option value="${l.department}" selected>${l.department}</option>`:""}\n                         </select>\n                     </div>\n                 </div>\n                 \n                 \x3c!-- Evidence Image Preview --\x3e\n                 <div id="evidence-preview-${d}" style="display: ${l.evidenceImage?"block":"none"}; margin-bottom: 0.5rem;">\n                     <div style="display: flex; align-items: center; gap: 0.5rem; padding: 0.5rem; background: #f0fdf4; border: 1px solid #bbf7d0; border-radius: var(--radius-sm);">\n                         <img id="evidence-img-${d}" src="${l.evidenceImage||""}" style="width: 60px; height: 60px; object-fit: cover; border-radius: 4px; cursor: pointer;" data-action="viewEvidenceImage" data-id="${d}" title="Click to enlarge">\n                         <div style="flex: 1;">\n                             <p style="margin: 0; font-size: 0.8rem; color: var(--success-color); font-weight: 500;"><i class="fa-solid fa-check-circle"></i> Image attached</p>\n                             <p id="evidence-size-${d}" style="margin: 0; font-size: 0.7rem; color: var(--text-secondary);">${l.evidenceSize||""}</p>\n                         </div>\n                         <button type="button" class="btn btn-sm" data-action="removeEvidence" data-id="${d}" style="color: var(--danger-color);" title="Remove" aria-label="Delete"><i class="fa-solid fa-trash"></i></button>\n                     </div>\n                 </div>\n                 <input type="hidden" id="evidence-data-${d}" value="${l.evidenceImage?"attached":""}">\n             </div>\n        </div>\n    `},"undefined"!=typeof module&&module.exports&&(module.exports=renderChecklistItemRow);